/**
 * Supabase Database — hand-rolled type surface.
 *
 * Generated by hand from `docs/database/migrations/0001_initial_schema.sql`
 * because the Supabase CLI requires a personal access token we haven't
 * provisioned yet. Replace this file the moment the access token lands:
 *
 *   pnpm dlx supabase gen types typescript \
 *     --project-id twebgqutuqgonabvhzjk    \
 *     --schema public                       \
 *     > apps/web/src/lib/supabase/types.ts
 *
 * Shape contract:
 *   - `Row`     : exactly what `.select()` returns for the table
 *   - `Insert`  : payload for `.insert()` (nullable defaults are optional)
 *   - `Update`  : payload for `.update()` (every column optional)
 *
 * jsonb columns are typed `Json` for flexibility — narrow them in
 * application code by casting through a typed helper.
 */

export type Json =
  | string
  | number
  | boolean
  | null
  | { [key: string]: Json | undefined }
  | Json[];

// ─── Enum values mirror migration 0001 ────────────────────────────────────
export type UserTier = "free" | "pro" | "premium" | "team" | "enterprise";
export type UserRoleEnum = "user" | "admin" | "owner";
export type OrgRole = "owner" | "admin" | "member" | "viewer";
export type OAuthProviderEnum = "google" | "linkedin" | "apple" | "microsoft";
export type ReportVisibility = "private" | "team" | "public" | "top-promote";
export type ReportTypeBadge = "Premium" | "PRO" | "Public" | "Private";
export type ReportStatus = "draft" | "published" | "archived";
export type ReportRoleEnum = "Principal" | "Broker" | "Lender" | "Developer";
export type ReportObjective =
  | "For Sale"
  | "Rent HMA"
  | "Lending"
  | "Develop"
  | "CoInvest";
export type SharePermission = "view" | "comment" | "edit";
export type LeadStatus =
  | "new"
  | "qualified"
  | "contacted"
  | "proposal"
  | "closed_won"
  | "closed_lost";
export type PdfStatus = "queued" | "generating" | "ready" | "failed";
export type ExcelStatus =
  | "queued"
  | "parsing"
  | "staged"
  | "applied"
  | "failed";
export type SubscriptionStatus =
  | "active"
  | "trialing"
  | "past_due"
  | "canceled"
  | "incomplete";
export type NotificationKind =
  | "tour_request"
  | "promotion_expiring"
  | "comment"
  | "share"
  | "system";

