      report_visibility: { Row: ReportVisibilityRow; Insert: InsertOf<ReportVisibilityRow>; Update: UpdateOf<ReportVisibilityRow>; Relationships: [] };
      report_shares: { Row: ReportSharesRow; Insert: InsertOf<ReportSharesRow>; Update: UpdateOf<ReportSharesRow>; Relationships: [] };

      investment_requirements: { Row: InvestmentRequirementsRow; Insert: InsertOf<InvestmentRequirementsRow>; Update: UpdateOf<InvestmentRequirementsRow>; Relationships: [] };
      market_preferences: { Row: MarketPreferencesRow; Insert: InsertOf<MarketPreferencesRow>; Update: UpdateOf<MarketPreferencesRow>; Relationships: [] };
      valuation_preferences: { Row: ValuationPreferencesRow; Insert: InsertOf<ValuationPreferencesRow>; Update: UpdateOf<ValuationPreferencesRow>; Relationships: [] };
      revpar_scenarios: { Row: RevparScenariosRow; Insert: InsertOf<RevparScenariosRow>; Update: UpdateOf<RevparScenariosRow>; Relationships: [] };
      hotel_filters: { Row: HotelFiltersRow; Insert: InsertOf<HotelFiltersRow>; Update: UpdateOf<HotelFiltersRow>; Relationships: [] };

