      report_files: { Row: ReportFilesRow; Insert: InsertOf<ReportFilesRow>; Update: UpdateOf<ReportFilesRow>; Relationships: [] };
      generated_pdfs: { Row: GeneratedPdfsRow; Insert: InsertOf<GeneratedPdfsRow>; Update: UpdateOf<GeneratedPdfsRow>; Relationships: [] };
      uploaded_excels: { Row: UploadedExcelsRow; Insert: InsertOf<UploadedExcelsRow>; Update: UpdateOf<UploadedExcelsRow>; Relationships: [] };
      renders: { Row: RendersRow; Insert: InsertOf<RendersRow>; Update: UpdateOf<RendersRow>; Relationships: [] };
